style:
.demo[data-v-coalescing] {
  max-width: 680px;
  margin: 0 auto;
  font-family: -apple-system, 'PingFang SC', sans-serif;
  color: #1f2329;
}
.bar[data-v-coalescing] {
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-bottom: 8px;
}
.seg-btns button[data-v-coalescing] {
  font: inherit;
  cursor: pointer;
  background: #fff;
  color: #1f2329;
  border: 1px solid #d9dee5;
  padding: 6px 14px;
  font-size: 0.85rem;
}
.seg-btns button[data-v-coalescing]:first-child {
  border-radius: 6px 0 0 6px;
}
.seg-btns button[data-v-coalescing]:last-child {
  border-radius: 0 6px 6px 0;
  border-left: none;
}
.seg-btns button.on[data-v-coalescing] {
  background: rgba(22, 119, 255, 0.1);
  border-color: #1677ff;
  color: #1677ff;
}
.metrics[data-v-coalescing] {
  font-size: 0.85rem;
  color: #8a909c;
}
.metrics b[data-v-coalescing] {
  color: #1677ff;
  font-size: 1.05rem;
  transition: color 0.4s;
}
.metrics b.bad[data-v-coalescing] {
  color: #cf1322;
}
.metrics .sep[data-v-coalescing] {
  margin: 0 8px;
}
.stage[data-v-coalescing] {
  width: 100%;
  background: #f8fafc;
  border: 1px solid #e2e6ed;
  border-radius: 10px;
}
.lbl[data-v-coalescing] {
  text-anchor: middle;
  font-size: 11px;
  font-weight: 600;
}
.cap-lbl[data-v-coalescing] {
  font-size: 11px;
  fill: #8a909c;
}
/* CSS transition 把状态变化自动变成动画，无需任何动画库 */
.cell[data-v-coalescing] {
  transition: fill 0.45s ease;
}
.marker[data-v-coalescing] {
  transition: transform 0.5s cubic-bezier(0.4, 0, 0.2, 1);
}
.seg-box[data-v-coalescing] {
  fill: transparent;
  stroke: #cbd2dc;
  stroke-dasharray: 4 4;
  opacity: 0.7;
  transition: opacity 0.45s, stroke 0.45s;
}
.seg-box.active[data-v-coalescing] {
  stroke: #1677ff;
  stroke-dasharray: none;
  opacity: 1;
}
.cap[data-v-coalescing] {
  font-size: 0.85rem;
  line-height: 1.7;
  color: #5c6370;
  margin-top: 10px;
}
.cap b[data-v-coalescing] {
  color: #1677ff;
}

